import { contextBridge, ipcRenderer } from 'electron';
import { Channels } from '../shared/channels';
import type {
  ActionEvent,
  AppConfig,
  CursorPosition,
  MouseClickEvent,
  OverlaySettings,
  PreviewSelection,
  WindowBounds,
} from '../shared/types';

const mainAPI = {
  onPreviewUpdate: (callback: (selection: PreviewSelection) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, selection: PreviewSelection): void =>
      callback(selection);
    ipcRenderer.removeAllListeners(Channels.PREVIEW_UPDATE);
    ipcRenderer.on(Channels.PREVIEW_UPDATE, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.PREVIEW_UPDATE, handler);
    };
  },
  onOverlayUpdate: (callback: (settings: OverlaySettings) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, settings: OverlaySettings): void =>
      callback(settings);
    ipcRenderer.removeAllListeners(Channels.OVERLAY_UPDATE);
    ipcRenderer.on(Channels.OVERLAY_UPDATE, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.OVERLAY_UPDATE, handler);
    };
  },
  onRecordingStart: (callback: (micDeviceId: string | null) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, micDeviceId: string | null): void =>
      callback(micDeviceId);
    ipcRenderer.removeAllListeners(Channels.MAIN_RECORDING_START);
    ipcRenderer.on(Channels.MAIN_RECORDING_START, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.MAIN_RECORDING_START, handler);
    };
  },
  signalRecordingReady: (): void => {
    ipcRenderer.send(Channels.MAIN_RECORDING_READY);
  },
  onRecordingStop: (callback: () => void): (() => void) => {
    const handler = (): void => callback();
    ipcRenderer.removeAllListeners(Channels.MAIN_RECORDING_STOP);
    ipcRenderer.on(Channels.MAIN_RECORDING_STOP, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.MAIN_RECORDING_STOP, handler);
    };
  },
  onRecordingPause: (callback: () => void): (() => void) => {
    const handler = (): void => callback();
    ipcRenderer.removeAllListeners(Channels.MAIN_RECORDING_PAUSE);
    ipcRenderer.on(Channels.MAIN_RECORDING_PAUSE, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.MAIN_RECORDING_PAUSE, handler);
    };
  },
  onRecordingResume: (callback: () => void): (() => void) => {
    const handler = (): void => callback();
    ipcRenderer.removeAllListeners(Channels.MAIN_RECORDING_RESUME);
    ipcRenderer.on(Channels.MAIN_RECORDING_RESUME, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.MAIN_RECORDING_RESUME, handler);
    };
  },
  saveRecording: (filePath: string, buffer: ArrayBuffer): Promise<void> =>
    ipcRenderer.invoke(Channels.FILE_SAVE_RECORDING, { filePath, buffer }) as Promise<void>,
  exportRecording: (): Promise<string> => ipcRenderer.invoke(Channels.RECORDING_EXPORT),
  preparePlayback: (buffer: ArrayBuffer): Promise<string> =>
    ipcRenderer.invoke(Channels.RECORDING_PREPARE_PLAYBACK, buffer),
  cleanupPlayback: (): Promise<void> => ipcRenderer.invoke(Channels.RECORDING_CLEANUP_PLAYBACK),
  getConfig: (): Promise<AppConfig> => ipcRenderer.invoke(Channels.CONFIG_GET),
  startMouseTracking: (): Promise<boolean> => ipcRenderer.invoke(Channels.MOUSE_TRACKING_START),
  stopMouseTracking: (): Promise<boolean> => ipcRenderer.invoke(Channels.MOUSE_TRACKING_STOP),
  onMousePosition: (callback: (position: CursorPosition) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, position: CursorPosition): void =>
      callback(position);
    ipcRenderer.removeAllListeners(Channels.MOUSE_POSITION);
    ipcRenderer.on(Channels.MOUSE_POSITION, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.MOUSE_POSITION, handler);
    };
  },
  onMouseClick: (callback: (event: MouseClickEvent) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, event: MouseClickEvent): void =>
      callback(event);
    ipcRenderer.removeAllListeners(Channels.MOUSE_CLICK);
    ipcRenderer.on(Channels.MOUSE_CLICK, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.MOUSE_CLICK, handler);
    };
  },
  getWindowBounds: (sourceId: string): Promise<WindowBounds | null> =>
    ipcRenderer.invoke(Channels.WINDOW_GET_BOUNDS, sourceId),
  selectScreenSource: (sourceId: string): Promise<void> =>
    ipcRenderer.invoke(Channels.DEVICES_SELECT_SCREEN_SOURCE, sourceId) as Promise<void>,
  hideSystemCursor: (): Promise<boolean> =>
    ipcRenderer.invoke(Channels.CURSOR_HIDE) as Promise<boolean>,
  showSystemCursor: (): Promise<boolean> =>
    ipcRenderer.invoke(Channels.CURSOR_SHOW) as Promise<boolean>,
  onCtaTest: (callback: () => void): (() => void) => {
    const handler = (): void => callback();
    ipcRenderer.removeAllListeners(Channels.CTA_TEST);
    ipcRenderer.on(Channels.CTA_TEST, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.CTA_TEST, handler);
    };
  },
  onActionEvent: (callback: (event: ActionEvent) => void): (() => void) => {
    const handler = (_event: Electron.IpcRendererEvent, actionEvent: ActionEvent): void =>
      callback(actionEvent);
    ipcRenderer.removeAllListeners(Channels.ACTION_EVENT);
    ipcRenderer.on(Channels.ACTION_EVENT, handler);
    return (): void => {
      ipcRenderer.removeListener(Channels.ACTION_EVENT, handler);
    };
  },
};

contextBridge.exposeInMainWorld('mainAPI', mainAPI);
